self.addEventListener("push",t=>{if(!t.data)return;let i=t.data.json(),n={body:i.body,icon:i.icon||"/icon-192.png",badge:"/icon-192.png",tag:i.tag||"miniplay",data:{url:i.url||"/"}};t.waitUntil(self.registration.showNotification(i.title,n))}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data&&t.notification.data.url||"/";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{for(let n of t)if(new URL(n.url).pathname===i&&"focus"in n)return n.focus();return self.clients.openWindow(i)}))});